#!/bin/bash

# Check if the script has been called with exactly one argument
if [ $# -ne 1 ]; then
    echo "Usage: $0 <logfile>"
    exit 1
fi

LOGFILE=$1
ARCHIVE_DIR="/archive/"

# If LOGFILE starts with a slash, remove it
if [[ ${LOGFILE} == /* ]]; then
    LOGFILE=${LOGFILE:1}
fi

# Create the archive directory if it doesn't exist
mkdir -p "$ARCHIVE_DIR/$(dirname $LOGFILE)"

# Copy the log file to the archive directory
cp "/var/log/$LOGFILE" "$ARCHIVE_DIR/$LOGFILE"